patch:
diff --git a/llvm/lib/Transforms/Utils/SimplifyCFG.cpp b/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
index 48055ad6ea7e..42f4fc2c6f05 100644
--- a/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
+++ b/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
@@ -5813,6 +5813,7 @@ bool SimplifyCFGOpt::turnSwitchRangeIntoICmp(SwitchInst *SI,
   assert(!CasesA.empty() || HasDefault);

   // Figure out if one of the sets of cases form a contiguous range.
+  SmallVector<ConstantInt *, 16> ComplementCases;
   SmallVectorImpl<ConstantInt *> *ContiguousCases = nullptr;
   BasicBlock *ContiguousDest = nullptr;
   BasicBlock *OtherDest = nullptr;
@@ -5824,7 +5825,28 @@ bool SimplifyCFGOpt::turnSwitchRangeIntoICmp(SwitchInst *SI,
     ContiguousCases = &CasesB;
     ContiguousDest = DestB;
     OtherDest = DestA;
-  } else
+  } else if (CasesA.empty() && HasDefault) {
+    // All explicit cases go to DestB, and the default goes to DestA.
+    // Check if the complement of CasesB within the known range of the
+    // condition is a contiguous range.
+    ConstantRange CR = computeConstantRange(
+        SI->getCondition(), /*ForSigned=*/false, /*UseInstrInfo=*/true,
+        Options.AC, SI);
+    if (!CR.isFullSet() && !CR.isEmptySet() &&
+        !CR.isSizeLargerThan(64)) {
+      for (APInt V = CR.getLower(); V != CR.getUpper(); ++V)
+        if (!llvm::is_contained(CasesB, ConstantInt::get(SI->getContext(), V)))
+          ComplementCases.push_back(
+              ConstantInt::get(SI->getContext(), V));
+      if (!ComplementCases.empty() && casesAreContiguous(ComplementCases)) {
+        ContiguousCases = &ComplementCases;
+        ContiguousDest = DestA;
+        OtherDest = DestB;
+      }
+    }
+  }
+
+  if (!ContiguousCases)
     return false;

   // Start building the compare and branch.

